function.arguments:
{"db_name":"products_orders","query":"SELECT pbe.Id as PricebookEntryId, pbe.Product2Id, pbe.UnitPrice as CatalogUnitPrice, pb.Id as Pricebook2Id, pb.Name as PricebookName, pb.IsActive, pb.ValidFrom, pb.ValidTo
FROM PricebookEntry pbe
JOIN Pricebook2 pb ON pb.Id = pbe.Pricebook2Id
WHERE TRIM(REPLACE(pbe.Id,'#','')) IN (
  SELECT DISTINCT TRIM(REPLACE(PricebookEntryId,'#',''))
  FROM (
    SELECT PricebookEntryId
    FROM (
      SELECT PricebookEntryId, QuoteId FROM (
        SELECT PricebookEntryId, QuoteId FROM PricebookEntry LIMIT 0
      )
    )
  )
);
"}

